/**
 * Pure tool library for the rerun-3d-mcp package.
 *
 * Exports `TOOL_DEFINITIONS` and `dispatchTool` so this package can be
 * consumed both by its own stdio entrypoint (`./index.ts`) and by the hosted
 * `mcp-gateway` which multiplexes all verticals behind a single HTTP endpoint.
 */
import { generateSetupProject, SETUP_PLATFORMS, } from "./setup-project.js";
import { generateArLogger, LOGGER_LANGUAGES, LOGGER_DATA_TYPES, } from "./ar-logger.js";
import { generatePythonSidecar, } from "./python-sidecar.js";
import { generateWebViewerEmbed, } from "./web-viewer-embed.js";
import { explainConcept, RERUN_CONCEPTS, } from "./concepts.js";
// ─── Legal disclaimer ─────────────────────────────────────────────────────────
const DISCLAIMER = "\n\n---\n*Generated by rerun-3d-mcp. Review before production use. Rerun is a trademark of Rerun AB — this MCP is not affiliated. See [LICENSE](https://github.com/sceneview/sceneview/blob/main/mcp/packages/rerun/LICENSE).*";
function withDisclaimer(content) {
    if (content.length === 0)
        return content;
    const last = content[content.length - 1];
    return [
        ...content.slice(0, -1),
        { ...last, text: last.text + DISCLAIMER },
    ];
}
// ─── Tool definitions ─────────────────────────────────────────────────────────
export const TOOL_DEFINITIONS = [
    {
        name: "setup_rerun_project",
        description: "Generates the minimum set of files a SceneView developer needs to start logging to Rerun. Supports Android (Gradle + Kotlin composable), iOS (Package.swift + SwiftUI view), Web (HTML with the Rerun Web Viewer WASM module embedded next to a SceneView canvas), and a standalone Python pipeline. Optionally bundles a Python sidecar script that receives the JSON-lines wire format from the device and re-logs it into the Rerun viewer.",
        inputSchema: {
            type: "object",
            properties: {
                platform: {
                    type: "string",
                    enum: SETUP_PLATFORMS,
                    description: `Target platform:\n${SETUP_PLATFORMS.map((p) => `- "${p}"`).join("\n")}`,
                },
                targetDir: {
                    type: "string",
                    description: 'Relative target directory for the generated files (default: ".").',
                },
                includeSidecar: {
                    type: "boolean",
                    description: "Bundle the Python sidecar script alongside the platform output. Default: true for android/ios, false for web/python.",
                },
            },
            required: ["platform"],
        },
    },
    {
        name: "generate_ar_logger",
        description: "Returns a ready-to-paste Kotlin (Jetpack Compose) or Swift (SwiftUI) helper that streams an AR session to Rerun. Pick which data types to log — camera pose, detected planes, point clouds, anchors, hit results — and the optional throttle (default 10 Hz). The generated code uses the RerunBridge helper (arsceneview.rerun.RerunBridge on Android, SceneViewSwift.RerunBridge on iOS) and drops frames on backpressure so the main thread is never blocked.",
        inputSchema: {
            type: "object",
            properties: {
                language: {
                    type: "string",
                    enum: LOGGER_LANGUAGES,
                    description: `Target language:\n${LOGGER_LANGUAGES.map((l) => `- "${l}"`).join("\n")}`,
                },
                dataTypes: {
                    type: "array",
                    items: { type: "string", enum: LOGGER_DATA_TYPES },
                    description: `Data types to log:\n${LOGGER_DATA_TYPES.map((d) => `- "${d}"`).join("\n")}`,
                },
                rateHz: {
                    type: "number",
                    description: "Throttle rate in Hz. Default: 10.",
                },
                host: {
                    type: "string",
                    description: 'Socket host. Default: "127.0.0.1".',
                },
                port: {
                    type: "number",
                    description: "Socket port. Default: 9876.",
                },
            },
            required: ["language", "dataTypes"],
        },
    },
    {
        name: "generate_python_sidecar",
        description: "Returns a standalone Python script that listens on a TCP port for the JSON-lines wire format emitted by a SceneView RerunBridge client (Android or iOS) and re-logs each event into the Rerun viewer as the matching archetype (Transform3D for poses, Points3D for clouds, LineStrips3D for plane boundaries). Useful for AR debugging sessions — run it on your dev machine while your device runs the sample app.",
        inputSchema: {
            type: "object",
            properties: {
                port: {
                    type: "number",
                    description: "TCP port to listen on. Default: 9876.",
                },
                recordingName: {
                    type: "string",
                    description: 'Rerun application id that shows in the viewer. Default: "sceneview-bridge".',
                },
                spawnViewer: {
                    type: "boolean",
                    description: "Automatically spawn the Rerun viewer process. Default: true.",
                },
            },
        },
    },
    {
        name: "embed_web_viewer",
        description: "Returns an HTML + module-script snippet that embeds the Rerun Web Viewer (WASM) in a web page, pointing at a .rrd file you host. Useful for publishing playback-ready AR sessions next to your SceneView canvas in documentation, landing pages, or sample pages. Returns three views of the same embed: the bare container HTML, the <script type=\"module\"> block, and a standalone HTML document. Optionally pins a specific Rerun viewer version and/or a time range.",
        inputSchema: {
            type: "object",
            properties: {
                rrdUrl: {
                    type: "string",
                    description: "URL of the .rrd file to load at startup.",
                },
                containerId: {
                    type: "string",
                    description: 'CSS id of the container div (letters/digits/underscore/dash only). Default: "rerun-viewer".',
                },
                hideWelcome: {
                    type: "boolean",
                    description: "Hide the Rerun welcome screen. Default: true.",
                },
                viewerVersion: {
                    type: "string",
                    description: 'Rerun Web Viewer version to load from jsdelivr. Default: "latest".',
                },
                timeRange: {
                    type: "array",
                    items: { type: "number" },
                    description: "Optional [startNanos, endNanos] to jump to on load.",
                },
            },
            required: ["rrdUrl"],
        },
    },
    {
        name: "explain_concept",
        description: "Returns a focused, SceneView-developer-friendly explanation of a single Rerun concept: rrd file format, timelines, entity paths, archetypes (Transform3D/Points3D/Mesh3D/etc.), or the coordinate system and transform conventions. Use this to onboard developers to Rerun without them having to read the full docs.",
        inputSchema: {
            type: "object",
            properties: {
                concept: {
                    type: "string",
                    enum: RERUN_CONCEPTS,
                    description: `Concept to explain:\n${RERUN_CONCEPTS.map((c) => `- "${c}"`).join("\n")}`,
                },
            },
            required: ["concept"],
        },
    },
];
// ─── Dispatcher ───────────────────────────────────────────────────────────────
/**
 * Dispatch a tool call by name. Pure business logic: no auth, no rate
 * limiting, no billing. Those concerns live in the caller (stdio server or
 * gateway).
 */
export async function dispatchTool(toolName, rawArgs, _ctx = {}) {
    switch (toolName) {
        // ── setup_rerun_project ───────────────────────────────────────────────
        case "setup_rerun_project": {
            const args = rawArgs ?? {};
            const platform = args.platform;
            if (!platform || !SETUP_PLATFORMS.includes(platform)) {
                return {
                    content: [
                        {
                            type: "text",
                            text: `Invalid platform "${platform}". Valid: ${SETUP_PLATFORMS.join(", ")}`,
                        },
                    ],
                    isError: true,
                };
            }
            const result = generateSetupProject({
                platform,
                targetDir: args.targetDir,
                includeSidecar: args.includeSidecar,
            });
            const body = [
                `## Rerun setup — ${platform}`,
                ``,
                `### Files`,
                ``,
            ];
            for (const f of result.files) {
                body.push(`**\`${f.path}\`**`);
                body.push("```" + f.language);
                body.push(f.contents.trimEnd());
                body.push("```");
                body.push("");
            }
            body.push(`### Instructions`, ``);
            for (const step of result.instructions) {
                body.push(`- ${step}`);
            }
            return {
                content: withDisclaimer([{ type: "text", text: body.join("\n") }]),
            };
        }
        // ── generate_ar_logger ────────────────────────────────────────────────
        case "generate_ar_logger": {
            const args = rawArgs ?? {};
            const language = args.language;
            const dataTypes = args.dataTypes;
            if (!language || !LOGGER_LANGUAGES.includes(language)) {
                return {
                    content: [
                        {
                            type: "text",
                            text: `Invalid language "${language}". Valid: ${LOGGER_LANGUAGES.join(", ")}`,
                        },
                    ],
                    isError: true,
                };
            }
            if (!dataTypes || !Array.isArray(dataTypes) || dataTypes.length === 0) {
                return {
                    content: [
                        {
                            type: "text",
                            text: `At least one dataType is required. Valid: ${LOGGER_DATA_TYPES.join(", ")}`,
                        },
                    ],
                    isError: true,
                };
            }
            let code;
            try {
                code = generateArLogger({
                    language,
                    dataTypes,
                    rateHz: args.rateHz,
                    host: args.host,
                    port: args.port,
                });
            }
            catch (err) {
                return {
                    content: [
                        {
                            type: "text",
                            text: `Error: ${err.message}`,
                        },
                    ],
                    isError: true,
                };
            }
            const langLabel = language === "kotlin" ? "Kotlin (Jetpack Compose)" : "Swift (SwiftUI)";
            const fence = language === "kotlin" ? "kotlin" : "swift";
            return {
                content: withDisclaimer([
                    {
                        type: "text",
                        text: [
                            `## AR logger — ${langLabel}`,
                            ``,
                            `**Data types:** ${dataTypes.join(", ")}`,
                            ``,
                            `**${langLabel}:**`,
                            "```" + fence,
                            code,
                            "```",
                        ].join("\n"),
                    },
                ]),
            };
        }
        // ── generate_python_sidecar ───────────────────────────────────────────
        case "generate_python_sidecar": {
            const args = rawArgs ?? {};
            let code;
            try {
                code = generatePythonSidecar({
                    port: args.port,
                    recordingName: args.recordingName,
                    spawnViewer: args.spawnViewer,
                });
            }
            catch (err) {
                return {
                    content: [
                        {
                            type: "text",
                            text: `Error: ${err.message}`,
                        },
                    ],
                    isError: true,
                };
            }
            return {
                content: withDisclaimer([
                    {
                        type: "text",
                        text: [
                            `## Python sidecar — rerun-bridge.py`,
                            ``,
                            `Run with: \`pip install rerun-sdk numpy && python rerun-bridge.py\``,
                            ``,
                            "```python",
                            code,
                            "```",
                        ].join("\n"),
                    },
                ]),
            };
        }
        // ── embed_web_viewer ──────────────────────────────────────────────────
        case "embed_web_viewer": {
            const args = rawArgs ?? {};
            const rrdUrl = args.rrdUrl;
            if (!rrdUrl || typeof rrdUrl !== "string" || !rrdUrl.trim()) {
                return {
                    content: [
                        { type: "text", text: "rrdUrl is required." },
                    ],
                    isError: true,
                };
            }
            const timeRangeRaw = args.timeRange;
            const timeRange = timeRangeRaw && timeRangeRaw.length === 2
                ? [timeRangeRaw[0], timeRangeRaw[1]]
                : undefined;
            let result;
            try {
                result = generateWebViewerEmbed({
                    rrdUrl,
                    containerId: args.containerId,
                    hideWelcome: args.hideWelcome,
                    viewerVersion: args.viewerVersion,
                    timeRange,
                });
            }
            catch (err) {
                return {
                    content: [
                        { type: "text", text: `Error: ${err.message}` },
                    ],
                    isError: true,
                };
            }
            return {
                content: withDisclaimer([
                    {
                        type: "text",
                        text: [
                            `## Rerun Web Viewer embed`,
                            ``,
                            `**Container HTML:**`,
                            "```html",
                            result.html,
                            "```",
                            ``,
                            `**Module script:**`,
                            "```html",
                            result.script,
                            "```",
                            ``,
                            `**Full standalone document:**`,
                            "```html",
                            result.fullDocument.trimEnd(),
                            "```",
                        ].join("\n"),
                    },
                ]),
            };
        }
        // ── explain_concept ───────────────────────────────────────────────────
        case "explain_concept": {
            const args = rawArgs ?? {};
            const concept = args.concept;
            if (!concept || !RERUN_CONCEPTS.includes(concept)) {
                return {
                    content: [
                        {
                            type: "text",
                            text: `Invalid concept "${concept}". Valid: ${RERUN_CONCEPTS.join(", ")}`,
                        },
                    ],
                    isError: true,
                };
            }
            return {
                content: [{ type: "text", text: explainConcept(concept) }],
            };
        }
        default:
            return {
                content: [
                    {
                        type: "text",
                        text: `Unknown tool: "${toolName}". Available: setup_rerun_project, generate_ar_logger, generate_python_sidecar, embed_web_viewer, explain_concept`,
                    },
                ],
                isError: true,
            };
    }
}
